import{_ as E,C as n,o as e,c as r,aQ as o,b as c,w as a,a as i,E as s,aR as l}from"./chunks/framework.cDvftfeu.js";const C=JSON.parse('{"title":"Ham Connect","description":"Ham Connect SSOプラットフォームの概要と機能。","frontmatter":{"description":"Ham Connect SSOプラットフォームの概要と機能。","prev":{"text":"開発概要","link":"/ja/developers/"},"next":{"text":"接続ガイド","link":"/ja/developers/open-platform/oauth2-guide"}},"headers":[],"relativePath":"ja/developers/open-platform/index.md","filePath":"ja/developers/open-platform/index.md","lastUpdated":1777525243000}'),A={name:"ja/developers/open-platform/index.md"};function h(B,t,u,p,m,_){const d=n("Mermaid");return e(),r("div",null,[t[1]||(t[1]=o('<h1 id="ham-connect" tabindex="-1">Ham Connect <a class="header-anchor" href="#ham-connect" aria-label="Permalink to &quot;Ham Connect&quot;">​</a></h1><p>Ham Connectは、Hamオープンプラットフォームが提供するOAuth 2.0認可サービスで、サードパーティアプリケーションがHamユーザーの認可情報を安全に取得できるようにします。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>Ham Connectは標準の <strong>OAuth 2.0 Authorization Code Grant</strong>（RFC 6749 §4.1）に基づいて実装されています。サードパーティアプリケーションはHam Connectを通じて「Hamでログイン」機能を実装し、ユーザーの認可後に基本情報を取得できます。</p><h3 id="対応スコープ" tabindex="-1">対応スコープ <a class="header-anchor" href="#対応スコープ" aria-label="Permalink to &quot;対応スコープ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>スコープ</th><th>説明</th><th>返却フィールド</th></tr></thead><tbody><tr><td><code>profile</code></td><td>ユーザーのニックネームとアバターにアクセス</td><td><code>nickname</code>、<code>avatar_url</code></td></tr><tr><td><code>is_student</code></td><td>ユーザーが学生かどうかにアクセス</td><td><code>is_student</code>（bool）</td></tr></tbody></table><blockquote><p><code>open_id</code>（現在のアプリケーションにおけるユーザーの一意識別子）は常に返却され、追加のスコープは不要です。</p></blockquote><h2 id="oauth2-インタラクションフロー" tabindex="-1">OAuth2 インタラクションフロー <a class="header-anchor" href="#oauth2-インタラクションフロー" aria-label="Permalink to &quot;OAuth2 インタラクションフロー&quot;">​</a></h2>',8)),(e(),c(l,null,{default:a(()=>[s(d,{id:"mermaid-62",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20U%20as%20%E3%83%A6%E3%83%BC%E3%82%B6%E3%83%BC%0A%20%20%20%20participant%20TP%20as%20%E3%82%B5%E3%83%BC%E3%83%89%E3%83%91%E3%83%BC%E3%83%86%E3%82%A3%E3%82%A2%E3%83%97%E3%83%AA%0A%20%20%20%20participant%20APP%20as%20Ham%0A%20%20%20%20participant%20BE%20as%20Ham%E3%82%AA%E3%83%BC%E3%83%97%E3%83%B3%E3%83%97%E3%83%A9%E3%83%83%E3%83%88%E3%83%95%E3%82%A9%E3%83%BC%E3%83%A0%0A%0A%20%20%20%20U-%3E%3ETP%3A%20%E3%80%8CHam%E3%81%A7%E3%83%AD%E3%82%B0%E3%82%A4%E3%83%B3%E3%80%8D%E3%82%92%E3%82%AF%E3%83%AA%E3%83%83%E3%82%AF%0A%20%20%20%20TP-%3E%3ETP%3A%20%E3%83%A9%E3%83%B3%E3%83%80%E3%83%A0%E3%81%AAstate%E3%82%92%E7%94%9F%E6%88%90%E3%81%97%E3%80%81%E3%82%BB%E3%83%83%E3%82%B7%E3%83%A7%E3%83%B3%E3%81%AB%E7%B4%90%E4%BB%98%E3%81%91%0A%20%20%20%20TP-%3E%3EAPP%3A%20Universal%20Link%E3%82%92%E9%96%8B%E3%81%84%E3%81%A6Ham%E3%82%92%E8%B5%B7%E5%8B%95%0A%20%20%20%20APP-%3E%3EU%3A%20%E8%AA%8D%E5%8F%AF%E3%83%9A%E3%83%BC%E3%82%B8%E3%82%92%E8%A1%A8%E7%A4%BA%EF%BC%88%E3%82%A2%E3%83%97%E3%83%AA%E6%83%85%E5%A0%B1%20%2B%20%E3%82%B9%E3%82%B3%E3%83%BC%E3%83%97%E4%B8%80%E8%A6%A7%EF%BC%89%0A%20%20%20%20U-%3E%3EAPP%3A%20%E3%80%8C%E5%90%8C%E6%84%8F%E3%80%8D%E3%82%92%E3%82%BF%E3%83%83%E3%83%97%0A%20%20%20%20APP-%3E%3ETP%3A%20redirect_uri%E3%81%AB%E3%83%AA%E3%83%80%E3%82%A4%E3%83%AC%E3%82%AF%E3%83%88%EF%BC%88code%E3%81%A8state%E3%82%92%E4%BB%98%E4%B8%8E%EF%BC%89%0A%20%20%20%20TP-%3E%3ETP%3A%20state%E3%81%AE%E4%B8%80%E8%87%B4%E6%80%A7%E3%82%92%E6%A4%9C%E8%A8%BC%0A%20%20%20%20TP-%3E%3EBE%3A%20POST%20%2Foauth%2Ftoken%EF%BC%88code%20%2B%20%E3%82%AF%E3%83%A9%E3%82%A4%E3%82%A2%E3%83%B3%E3%83%88%E8%AA%8D%E8%A8%BC%E6%83%85%E5%A0%B1%EF%BC%89%0A%20%20%20%20BE-%3E%3ETP%3A%20access_token%E3%82%92%E8%BF%94%E5%8D%B4%0A%20%20%20%20TP-%3E%3EBE%3A%20GET%20%2Foauth%2Fuserinfo%EF%BC%88Bearer%E3%83%88%E3%83%BC%E3%82%AF%E3%83%B3%20%2B%20%E3%82%AF%E3%83%A9%E3%82%A4%E3%82%A2%E3%83%B3%E3%83%88%E8%AA%8D%E8%A8%BC%E6%83%85%E5%A0%B1%EF%BC%89%0A%20%20%20%20BE-%3E%3ETP%3A%20open_id%20%2F%20nickname%20%2F%20avatar_url%20%E7%AD%89%E3%82%92%E8%BF%94%E5%8D%B4%0A%20%20%20%20TP-%3E%3EU%3A%20%E3%83%AD%E3%82%B0%E3%82%A4%E3%83%B3%E6%88%90%E5%8A%9F%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=o('<h3 id="フロー説明" tabindex="-1">フロー説明 <a class="header-anchor" href="#フロー説明" aria-label="Permalink to &quot;フロー説明&quot;">​</a></h3><ol><li><strong>認可の開始</strong>：サードパーティアプリがUniversal Link経由でHamを起動し、<code>client_id</code>、<code>scope</code>、<code>state</code>、<code>redirect_uri</code>パラメータを送信</li><li><strong>ユーザー認可</strong>：ユーザーがHamで認可情報を確認し、同意</li><li><strong>認可コードの取得</strong>：Hamがサードパーティアプリの<code>redirect_uri</code>にリダイレクトし、ワンタイム<code>code</code>を付与</li><li><strong>トークン交換</strong>：サードパーティの<strong>サーバー</strong>が<code>code</code> + <code>client_id</code> + <code>client_secret</code>で<code>access_token</code>を取得</li><li><strong>ユーザー情報の取得</strong>：サードパーティの<strong>サーバー</strong>が<code>access_token</code> + クライアント認証情報でユーザー情報をリクエスト</li></ol><h3 id="主要エンドポイント" tabindex="-1">主要エンドポイント <a class="header-anchor" href="#主要エンドポイント" aria-label="Permalink to &quot;主要エンドポイント&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エンドポイント</th><th>説明</th></tr></thead><tbody><tr><td><code>https://ham.nowcent.cn/sso-authorize</code></td><td>認可エントリ（Universal Link）、モバイル、デスクトップ（QRコードスキャン等）、Passkey認証に対応</td></tr><tr><td><code>https://open-api.ham.nowcent.cn/oauth/token</code></td><td>トークン交換</td></tr><tr><td><code>https://open-api.ham.nowcent.cn/oauth/userinfo</code></td><td>ユーザー情報の取得</td></tr></tbody></table><h3 id="トークンの有効期間" tabindex="-1">トークンの有効期間 <a class="header-anchor" href="#トークンの有効期間" aria-label="Permalink to &quot;トークンの有効期間&quot;">​</a></h3><table tabindex="0"><thead><tr><th>トークン</th><th>有効期間</th><th>備考</th></tr></thead><tbody><tr><td>Authorization Code</td><td>5分</td><td>ワンタイム使用、交換後に無効化</td></tr><tr><td>Access Token</td><td>2時間</td><td>期限切れ後は再認可が必要</td></tr><tr><td>Refresh Token</td><td>提供なし</td><td>—</td></tr></tbody></table><h2 id="client-id-と-client-secret-の取得" tabindex="-1">client_id と client_secret の取得 <a class="header-anchor" href="#client-id-と-client-secret-の取得" aria-label="Permalink to &quot;client_id と client_secret の取得&quot;">​</a></h2><p><code>client_id</code>と<code>client_secret</code>は、Ham Connectに接続するために必要な認証情報です：</p><ul><li><strong>client_id</strong>：アプリケーションの公開識別子、フロントエンドで使用可能</li><li><strong>client_secret</strong>：アプリケーションの機密認証情報、<strong>サーバーサイドでのみ使用</strong>してください。フロントエンドコード、モバイルアプリバンドル、公開リポジトリには絶対に含めないでください</li></ul><div class="warning custom-block"><p class="custom-block-title">申請方法</p><p>現在、<code>client_id</code>と<code>client_secret</code>は開発者に連絡して申請する必要があります。</p><p><a href="https://github.com/whu-ham/whu-ham.github.io/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a>からお問い合わせいただき、以下の情報をご提供ください：</p><ol><li>アプリケーション名と概要</li><li>コールバックURL（<code>redirect_uri</code>）ホワイトリスト</li><li>必要なスコープ</li></ol></div><h2 id="セキュリティに関する注意事項" tabindex="-1">セキュリティに関する注意事項 <a class="header-anchor" href="#セキュリティに関する注意事項" aria-label="Permalink to &quot;セキュリティに関する注意事項&quot;">​</a></h2><ul><li>すべてのAPI呼び出しは<strong>HTTPS</strong>を使用すること</li><li><code>client_secret</code>と<code>access_token</code>は<strong>サーバーサイドでのみ保存・使用</strong>すること</li><li>CSRF攻撃を防ぐため、<code>state</code>パラメータを常に使用・検証すること</li><li><strong>最小権限の原則</strong>に従い、業務に必要なスコープのみを申請すること</li><li>ユーザーの一意識別子として<code>open_id</code>を使用し、<code>nickname</code>に依存しないこと</li></ul><div class="tip custom-block"><p class="custom-block-title">完全なドキュメント</p><p>完全なAPI仕様、エラーコード、セキュリティベストプラクティスについては、<a href="./oauth2-guide.html">接続ガイド</a>をご参照ください。</p></div>',13))])}const P=E(A,[["render",h]]);export{C as __pageData,P as default};
